            var timestamp any = this.SafeInteger(response, "T")
            var orderbook any = this.ParseOrderBook(response, symbol, timestamp)
            AddElementToObject(orderbook, "nonce", this.SafeInteger2(response, "lastUpdateId", "u"))
        
