func  (this *BinanceCore) ParseOHLCV(ohlcv any, optionalArgs ...any) any  {
    // when api method = publicGetKlines || fapiPublicGetKlines || dapiPublicGetKlines
    //     [
    //         1591478520000, // open time
    //         "0.02501300",  // open
    //         "0.02501800",  // high
    //         "0.02500000",  // low
    //         "0.02500000",  // close
    //         "22.19000000", // volume
    //         1591478579999, // close time
    //         "0.55490906",  // quote asset volume, base asset volume for dapi
    //         40,            // number of trades
    //         "10.92900000", // taker buy base asset volume
    //         "0.27336462",  // taker buy quote asset volume
    //         "0"            // ignore
    //     ]
    //
    //  when api method = fapiPublicGetMarkPriceKlines || fapiPublicGetIndexPriceKlines
    //     [
    //         [
    //         1591256460000,          // Open time
    //         "9653.29201333",        // Open
    //         "9654.56401333",        // High
    //         "9653.07367333",        // Low
    //         "9653.07367333",        // Close (or latest price)
    //         "0",                    // Ignore
    //         1591256519999,          // Close time
    //         "0",                    // Ignore
    //         60,                     // Number of bisic data
    //         "0",                    // Ignore
    //         "0",                    // Ignore
    //         "0"                     // Ignore
    //         ]
    //     ]
    //
    // options
    //
    //     {
    //         "open": "32.2",
    //         "high": "32.2",
    //         "low": "32.2",
    //         "close": "32.2",
    //         "volume": "0",
    //         "interval": "5m",
    //         "tradeCount": 0,
    //         "takerVolume": "0",
    //         "takerAmount": "0",
    //         "amount": "0",
    //         "openTime": 1677096900000,
    //         "closeTime": 1677097200000
    //     }
    //
    market := GetArg(optionalArgs, 0, nil)
    _ = market
    var inverse any = this.SafeBool(market, "inverse")
    var volumeIndex any = Ternary(IsTrue(inverse), 7, 5)
    return []any{this.SafeInteger2(ohlcv, 0, "openTime"), this.SafeNumber2(ohlcv, 1, "open"), this.SafeNumber2(ohlcv, 2, "high"), this.SafeNumber2(ohlcv, 3, "low"), this.SafeNumber2(ohlcv, 4, "close"), this.SafeNumber2(ohlcv, volumeIndex, "volume")}
}
