    //         "maxQty": "15",
    //         "notionalValue": "0.00412454",
    //         "breakEvenPrice": "2423.368960034"
    //     }
    //
    // linear portfolio margin
    //
    //     {
    //         "symbol": "BTCUSDT",
    //         "positionAmt": "0.01",
    //         "entryPrice": "44525.0",
    //         "markPrice": "45464.1735922",
    //         "unRealizedProfit": "9.39173592",
